#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


//Shader from https://www.shadertoy.com/view/3ftSz2
//Ported to MilkDrop by MilkDrop2077

    vec4 o = vec4(0,0,0,0);
    float T = uTime;
    vec2 r = vec2(1.0, 1.0/uAspect.x);
    vec4 U = vec4(0,1,2,3);
    r.y = -r.y;

    for(float i=0.0, z=0.0, d=0.0; i<28.0; i+=1.0) {
        // Convert UV to ray direction
        vec2 centered_uv = (vUv-0.5)*r*2.0;
        vec4 p = vec4(z*normalize(vec3(centered_uv,1.0)),0);
        p.z -= 4.0;

        // Reset for plane accumulation
        d = 9e9;

        for(float j=5.0, D=0.0; j<9.0; j+=1.0) {
            // Plane thickness calculation
            D = 2.0/(j-3.0+q1)+p.y/3.0;

            // Apply distortion and rotation
            vec4 P = p;
            P.x -= 0.3*sin(p.y+T);

            // Create rotation matrix
            float angle = j-T+p.y+11.0*U.x;
            mat2 rot = transpose(mat2(cos(angle), -sin(angle), sin(angle), cos(angle)));
            P.xz = vec2(P.x*rot[0][0] + P.z*rot[0][1], P.x*rot[1][0] + P.z*rot[1][1]);
            // In GLSL is column-major order and in HLSL, row-major order,
            // So we transpose the matrix with transpose() to be the same as GLSL.

            // Mirror space
            P = abs(P)-0.01;

            // Distance field calculation
            float dist = min(
                max(P.z, P.x-D)+2E-2,
                length(P.xz-D*U.yx)
            );

            // Track closest distance
            d = min(d, dist);

            // Color generation
            vec4 P_color = 1.2+sin(j+U.xyzy+z);

            // Accumulate color
            o += P_color.w*P_color/max(dist,1E-3);
        }

        // Ray marching step
        z += 0.6*d + 1E-3;
    }

    // Tone mapping with music reactivity
    float brightness = 0.8 + 0.2*audioLowSmooth;
    ret = tanh(o/1e3 * brightness);

  fragColor = ret;
}

